class Solution:
    def maxAlternatingSum(self, nums):
        n = len(nums)
        if n <= 18:
            best = 0
            for mask in range(1, 1 << n):
                total = 0
                pos = 0
                for i in range(n):
                    if mask & (1 << i):
                        total += nums[i] if pos % 2 == 0 else -nums[i]
                        pos += 1
                if total > best:
                    best = total
            return best
        even, odd = 0, 0
        for x in nums:
            even, odd = max(even, odd + x), max(odd, even - x)
        return even

